import { SignJWT, jwtVerify } from 'jose';
import { NextRequest } from 'next/server';

const JWT_SECRET_KEY = process.env.JWT_SECRET_KEY || 'super-secret-development-key';
const encodedKey = new TextEncoder().encode(JWT_SECRET_KEY);

export interface SessionPayload {
  userId: string;
  email: string;
  role: string;
  type?: 'access' | 'refresh';
}

export async function signAccessToken(payload: Omit<SessionPayload, 'type'>) {
  return new SignJWT({ ...payload, type: 'access' } as any)
    .setProtectedHeader({ alg: 'HS256' })
    .setIssuedAt()
    .setExpirationTime('15m') // Short-lived access token
    .sign(encodedKey);
}

export async function signRefreshToken(payload: Omit<SessionPayload, 'type'>) {
  return new SignJWT({ ...payload, type: 'refresh' } as any)
    .setProtectedHeader({ alg: 'HS256' })
    .setIssuedAt()
    .setExpirationTime('7d') // Long-lived refresh token
    .sign(encodedKey);
}

export async function verifyToken(token: string) {
  try {
    const { payload } = await jwtVerify(token, encodedKey, {
      algorithms: ['HS256'],
    });
    return payload as unknown as SessionPayload;
  } catch (error) {
    return null;
  }
}

/**
 * Extracts and verifies the JWT token from the Authorization header or cookies.
 */
export async function getSession(request: NextRequest) {
  // 1. Check Bearer token (Primary for API)
  const authHeader = request.headers.get('Authorization');
  if (authHeader && authHeader.startsWith('Bearer ')) {
    const token = authHeader.split(' ')[1];
    const payload = await verifyToken(token);
    if (payload && payload.type === 'access') return payload;
  }

  // 2. Check cookies (Fallback for Server Components/Actions)
  const sessionCookie = request.cookies.get('access_token')?.value;
  if (sessionCookie) {
    const payload = await verifyToken(sessionCookie);
    if (payload && payload.type === 'access') return payload;
  }

  return null;
}

// Deprecated alias for backward compatibility during migration
export const encrypt = signAccessToken;
export const decrypt = verifyToken;
